// === READ RESUME FROM PDF ===
const rawText = $input.first().json.text;

if (!rawText || rawText.trim().length < 50) {
  throw new Error('Resume PDF appears empty or too short.');
}

// Clean up null characters introduced by PDF extraction
const resumeText = rawText.replace(/\u0000/g, '').trim();

const baseConfig = {
  minScore: 75,
  yourEmail: 'YOUR_EMAIL@gmail.com',
  spreadsheetId: 'YOUR_GOOGLE_SHEET_ID',
  openAiApiKey: 'YOUR_OPENAI_API_KEY',
  rapidApiKey: 'YOUR_RAPIDAPI_KEY',
  apifyToken: 'YOUR_APIFY_TOKEN',
  resumeText: resumeText
};

// 7 targeted JSearch searches covering .NET/C#/React roles, Bangalore only
return [
  { json: { ...baseConfig, searchQuery: '.NET Developer Bangalore India' } },
  { json: { ...baseConfig, searchQuery: 'Backend Engineer .NET Bangalore India' } },
  { json: { ...baseConfig, searchQuery: 'Full Stack Engineer React .NET Bangalore India' } },
  { json: { ...baseConfig, searchQuery: 'SDE 2 .NET Bangalore India' } },
  { json: { ...baseConfig, searchQuery: 'Senior Software Engineer .NET Bangalore India' } },
  { json: { ...baseConfig, searchQuery: 'C# Developer Bangalore India' } },
  { json: { ...baseConfig, searchQuery: 'Software Engineer II .NET Bangalore India' } },
];

const config = $input.first().json;

return [
  {
    json: {
      apifyToken: config.apifyToken,
      naukriJobTitle: '.NET Developer',
      naukriLocation: 'Bangalore'
    }
  }
];

const config = $input.first().json;

return [
  {
    json: {
      apifyToken: config.apifyToken,
      naukriJobTitle: 'C# Developer',
      naukriLocation: 'Bangalore'
    }
  }
];

const allItems = $input.all();
let allJobs = [];

function normalizeUrl(url) {
  if (!url) return '';
  try {
    const u = new URL(url);
    return (u.hostname + u.pathname).toLowerCase().replace(/\/$/, '');
  } catch(e) { return url.toLowerCase().trim().substring(0, 200); }
}

function hashJob(company, title, applyLink) {
  const raw = applyLink ? normalizeUrl(applyLink) : ((company || '').toLowerCase().trim() + '|' + (title || '').toLowerCase().trim());
  let hash = 0;
  for (let i = 0; i < raw.length; i++) {
    const char = raw.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return 'JOB_' + Math.abs(hash).toString(36);
}

for (const item of allItems) {
  if (item.json.data && Array.isArray(item.json.data)) {
    // JSearch format
    const jobs = item.json.data;
    const parsed = jobs.map(job => {
      const location = [job.job_city, job.job_state].filter(Boolean).join(', ') || 'Bangalore';
      let salary = 'Not listed';
      if (job.job_min_salary && job.job_max_salary) {
        salary = `${job.job_salary_currency || ''} ${job.job_min_salary}-${job.job_max_salary} ${job.job_salary_period || ''}`.trim();
      }
      const applyLink = job.job_apply_link || job.job_google_link || '';
      return {
        jobId: hashJob(job.employer_name, job.job_title, applyLink),
        title: job.job_title || 'Unknown Title',
        company: job.employer_name || 'Unknown Company',
        location,
        description: (job.job_description || '').substring(0, 3000),
        postedDate: job.job_posted_at_datetime_utc ? job.job_posted_at_datetime_utc.split('T')[0] : 'Unknown',
        applyLink,
        source: job.job_publisher || 'JSearch',
        salary,
        schedule: job.job_employment_type || ''
      };
    });
    allJobs.push(...parsed);
  } else if (Array.isArray(item.json)) {
    // Apify/Naukri format — apply_link is snake_case
    const jobs = item.json;
    const parsed = jobs.map(job => {
      const company = job.companyName || job.company || 'Unknown Company';
      const title = job.jobTitle || job.title || job.positionName || 'Unknown Title';
      const applyLink = job.apply_link || job.jobUrl || job.url || job.applyLink || '';
      return {
        jobId: hashJob(company, title, applyLink),
        title,
        company,
        location: job.location || job.jobLocation || job.city || 'Bangalore',
        description: (job.jobDescription || job.description || job.jobSummary || '').substring(0, 3000),
        postedDate: job.datePosted || job.postedDate || job.posted || job.date || 'Unknown',
        applyLink,
        source: 'Naukri',
        salary: job.salary || job.salaryRange || job.ctc || 'Not listed',
        schedule: job.employmentType || job.jobType || job.workplaceType || ''
      };
    });
    allJobs.push(...parsed);
  }
}

if (allJobs.length === 0) {
  throw new Error('No jobs found from any source. Check your API keys and queries.');
}

return { json: { jobs: allJobs, totalFound: allJobs.length } };

const allResults = $input.all();
const uniqueJobs = new Map();

for (const result of allResults) {
  const jobs = result.json.jobs || [];
  for (const job of jobs) {
    if (!uniqueJobs.has(job.jobId)) {
      uniqueJobs.set(job.jobId, job);
    }
  }
}

return Array.from(uniqueJobs.values()).map(job => ({ json: job }));

// Collapse N job items into 1 so Read Existing Jobs runs exactly once (not per-job)
const jobs = $input.all().map(item => item.json);
return [{ json: { jobs, count: jobs.length } }];

function normalizeUrl(url) {
  if (!url) return '';
  try {
    const u = new URL(url);
    return (u.hostname + u.pathname).toLowerCase().replace(/\/$/, '');
  } catch(e) { return url.toLowerCase().trim().substring(0, 200); }
}

const all = $input.all();

// Separate by shape: jobs item has {jobs:[...], count:N}, sheet rows have {Apply Link:...}
const jobsItem = all.find(i => Array.isArray(i.json.jobs));
const sheetRows = all.filter(i => !Array.isArray(i.json.jobs));

const jobs = jobsItem ? jobsItem.json.jobs : [];

const seenLinks = new Set(
  sheetRows.map(r => normalizeUrl(r.json['Apply Link'] || '')).filter(Boolean)
);
const seenTitles = new Set(
  sheetRows.map(r => ((r.json['Company'] || '') + '|' + (r.json['Job Title'] || '')).toLowerCase().trim()).filter(s => s !== '|')
);

const newJobs = jobs.filter(job => {
  const link = normalizeUrl(job.applyLink || '');
  if (link) return !seenLinks.has(link);
  const key = ((job.company || '') + '|' + (job.title || '')).toLowerCase().trim();
  return !seenTitles.has(key);
});

if (newJobs.length === 0) {
  throw new Error('No new jobs this week \u2014 all ' + jobs.length + ' results were already seen in previous runs.');
}

return newJobs.map(job => ({ json: job }));

// Prepare OpenAI payload for each job
const config = $('Set Job Preferences').first().json;

return $input.all().map(item => {
  const job = item.json;
  const resume = config.resumeText || '';
  const jobDesc = (job.description || '').substring(0, 3000);

  const aiPayload = JSON.stringify({
    model: 'gpt-4o-mini',
    messages: [
      {
        role: 'system',
        content: 'You are an expert recruiter. Grade job matches for a Backend-heavy Full Stack Developer (.NET/React) with 5 years experience targeting mid-to-senior roles (SDE 2, Senior Engineer, .NET Developer, Backend Engineer). Score the match 0-100. Penalize heavily if the role requires less than 2 years (too junior) or more than 8 years (too senior). Return a JSON object with exactly these fields: score (number 0-100), matchReason (string, 2-3 sentences), missingSkills (array of strings), keyMatchingSkills (array of strings), experienceFit (one of: good, overqualified, underqualified), recommendation (one of: strong-apply, apply, maybe, skip).'
      },
      {
        role: 'user',
        content: 'Analyze the match between this resume and job posting.\n\nRESUME:\n' + resume + '\n\nJOB POSTING:\n' + jobDesc
      }
    ],
    temperature: 0.1,
    response_format: { type: 'json_object' }
  });

  return {
    json: {
      ...job,
      openAiApiKey: config.openAiApiKey,
      aiPayload
    }
  };
});

const groqResponse = $input.item.json;
const job = $('Prepare Score Request').item.json;

const aiText = groqResponse.choices?.[0]?.message?.content || '{}';
let p = {};
try { p = JSON.parse(aiText); } catch(e) {}

return {
  json: {
    jobId: job.jobId,
    title: job.title,
    company: job.company,
    location: job.location,
    description: job.description,
    postedDate: job.postedDate,
    applyLink: job.applyLink,
    source: job.source,
    salary: job.salary,
    schedule: job.schedule,
    score: p.score || 0,
    matchReason: p.matchReason || '',
    missingSkills: p.missingSkills || [],
    keyMatchingSkills: p.keyMatchingSkills || [],
    experienceFit: p.experienceFit || 'unknown',
    recommendation: p.recommendation || 'skip'
  }
};

const items = $input.all();
const minScore = $('Set Job Preferences').first().json.minScore || 50;

const matched = items.filter(item => (item.json.score || 0) >= minScore);

if (matched.length === 0) {
  throw new Error(`No jobs scored above ${minScore}. Top score was ${Math.max(...items.map(i => i.json.score || 0))}. Try lowering minScore in Set Job Preferences.`);
}

return matched;

// Prepare OpenAI payload for cover letter generation
const config = $('Set Job Preferences').first().json;

return $input.all().map(item => {
  const job = item.json;
  const resume = config.resumeText || '';
  const jobDesc = (job.description || '').substring(0, 3000);

  const aiPayload = JSON.stringify({
    model: 'gpt-4o-mini',
    messages: [
      {
        role: 'system',
        content: 'You are a professional hiring manager. Write a tailored cover letter for a Senior .NET/React Developer with 5 years experience. Keep it under 300 words, no markdown, plain text only.'
      },
      {
        role: 'user',
        content: 'Write a professional cover letter.\n\nRESUME:\n' + resume + '\n\nJOB:\n' + jobDesc
      }
    ],
    temperature: 0.7
  });

  return {
    json: {
      ...job,
      openAiApiKey: config.openAiApiKey,
      aiPayload
    }
  };
});

const groqResponse = $input.item.json;
const job = $('Prepare Cover Letter').item.json;

const coverLetter = groqResponse.choices?.[0]?.message?.content || 'Cover letter generation failed.';

return {
  json: {
    ...job,
    coverLetter: coverLetter.trim(),
    processedDate: new Date().toISOString().split('T')[0]
  }
};

const items = $input.all();
const config = $('Set Job Preferences').first().json;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const getScore = j => Number(j['Match Score'] || j.score || 0);

if (items.length === 0) {
  return {
    json: {
      subject: `Job Search: No new matches found - ${today}`,
      htmlBody: `<html><body style="font-family: Arial, sans-serif;"><h2>Job Search Report - ${today}</h2><p>No new jobs matched your criteria (minimum score: ${config.minScore}).</p></body></html>`,
      matchCount: 0,
      topScore: 0,
      yourEmail: config.yourEmail
    }
  };
}

const sorted = items.map(i => i.json).sort((a, b) => getScore(b) - getScore(a));
const topScore = getScore(sorted[0]);

const jobRows = sorted.map(j => {
  const title = j['Job Title'] || j.title || 'Unknown Title';
  const company = j['Company'] || j.company || 'Unknown';
  const location = j['Location'] || j.location || 'Not specified';
  const score = getScore(j);
  const recommendation = j['Recommendation'] || j.recommendation || 'skip';
  const matchReason = j['Match Reason'] || j.matchReason || '';
  const missingSkills = j['Missing Skills'] || (j.missingSkills ? (Array.isArray(j.missingSkills) ? j.missingSkills.join(', ') : j.missingSkills) : '');
  const applyLink = j['Apply Link'] || j.applyLink || '#';
  const coverLetter = j['Cover Letter'] || j.coverLetter || '';
  const source = j.source || 'Google Jobs';
  const salary = j.salary || 'Not listed';
  const scoreColor = score >= 85 ? '#27ae60' : score >= 70 ? '#f39c12' : '#e74c3c';
  const recBadge = recommendation === 'strong-apply' ? 'Strong Apply' : recommendation === 'apply' ? 'Apply' : recommendation === 'maybe' ? 'Maybe' : 'Skip';
  return `<tr style="border-bottom: 1px solid #eee;"><td style="padding: 12px;"><strong>${title}</strong><br><span style="color: #666;">${company} - ${location}</span><br><span style="color: #888; font-size: 12px;">${source} | ${salary}</span></td><td style="padding: 12px; text-align: center;"><span style="background: ${scoreColor}; color: white; padding: 4px 12px; border-radius: 12px; font-weight: bold;">${score}</span></td><td style="padding: 12px; text-align: center;">${recBadge}</td><td style="padding: 12px;"><a href="${applyLink}" style="background: #3498db; color: white; padding: 8px 16px; border-radius: 4px; text-decoration: none;">Apply</a></td></tr><tr><td colspan="4" style="padding: 8px 12px; background: #f9f9f9;"><strong>Why it matches:</strong> ${matchReason}<br>${missingSkills ? '<strong>Missing:</strong> ' + missingSkills : ''}</td></tr><tr><td colspan="4" style="padding: 8px 12px; background: #f0f7ff;"><details><summary style="cursor: pointer; font-weight: bold;">Cover Letter</summary><div style="white-space: pre-wrap; margin-top: 8px; padding: 12px; background: white; border: 1px solid #ddd; border-radius: 4px;">${coverLetter}</div></details></td></tr>`;
}).join('');

const htmlBody = `<html><body style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto;"><div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 24px; border-radius: 8px 8px 0 0;"><h1 style="color: white; margin: 0;">Job Search Report</h1><p style="color: rgba(255,255,255,0.8); margin: 8px 0 0;">${today}</p></div><div style="background: #f5f5f5; padding: 16px;"><span style="background: white; padding: 12px 24px; border-radius: 8px; margin-right: 16px;"><strong style="font-size: 24px; color: #3498db;">${sorted.length}</strong> Matches</span><span style="background: white; padding: 12px 24px; border-radius: 8px;"><strong style="font-size: 24px; color: #27ae60;">${topScore}</strong> Top Score</span></div><table style="width: 100%; border-collapse: collapse; background: white;"><thead><tr style="background: #ecf0f1;"><th style="padding: 12px; text-align: left;">Job</th><th style="padding: 12px; text-align: center;">Score</th><th style="padding: 12px; text-align: center;">Action</th><th style="padding: 12px;">Link</th></tr></thead><tbody>${jobRows}</tbody></table><div style="padding: 16px; text-align: center; color: #888; font-size: 12px;">Generated by n8n Job Search Automation | Min score: ${config.minScore}</div></body></html>`;

return {
  json: {
    subject: `${sorted.length} Job Matches (Top: ${topScore}/100) - ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`,
    htmlBody,
    matchCount: sorted.length,
    topScore,
    yourEmail: config.yourEmail
  }
};

const emailData = $input.first().json;
return {
  json: {
    success: true,
    message: 'Job search automation completed!',
    matchCount: emailData.matchCount || 0,
    topScore: emailData.topScore || 0,
    emailSent: true,
    sentTo: emailData.yourEmail || 'unknown',
    timestamp: new Date().toISOString()
  }
};
